// TypeScript implementation for Property Decorators
interface PropertyDecoratorsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processPropertyDecorators(item: PropertyDecoratorsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processPropertyDecorators({ id: 1, title: 'Property Decorators', status: 'active' }));

